    /// <summary>
    ///
    /// </summary>
    public static boolean existsRunningInstanceForScope(UBSEndPointType _endPointType,RecId _currentExecution,DataAreaId _scope="")
    {
        UBSInterfaceExecutionHistoryTable execution;

        select firstonly execution where execution.UBSEndPointType == _endPointType
            && execution.UBSInterfaceStatus == UBSInterfaceStatus::InProcess
            && execution.RecId != _currentExecution
            && (execution.DimensionDataAreaId == "" || execution.DimensionDataAreaId == _scope);

        return execution.RecId != 0;
    }

    public static UBSInterfaceExecutionHistoryTable insertExecution(UBSEndPointType _endPointType,DataAreaId _scope ='')
    {
        UBSInterfaceExecutionHistoryTable execution;

        ttsbegin;

        execution.UBSEndPointType = _endPointType;
        execution.UBSInterfaceStatus = UBSInterfaceStatus::InProcess;
        execution.DimensionDataAreaId = _scope;
        execution.insert();

        ttscommit;

        return execution;
    }

    public void updateStatus(UBSInterfaceStatus _status,str _errorMessage='')
    {
        ttsbegin;

        this.selectForUpdate(true);
        this.UBSInterfaceStatus = _status;
        if(_errorMessage)
        {
            this.DMFErrorMessage = _errorMessage;
        }
        this.update();

        ttscommit;
    }
